external_knowledge:
- 'Sizable fan base' refers to artists having more than 100,000 followers;
- 'Popular artists' are defined as having a popularity score greater than 80;
- Danceability indicates how suitable a track is for dancing, based on a combination of musical elements;
- Total duration of albums is calculated as the sum of all tracks within the artist's album collection.

sql:
SELECT track_id, track_name 
FROM tracks 
WHERE track_id NOT IN (SELECT track_id FROM track_recommendations);

SELECT platform_artist_id
FROM artist_platform_data
WHERE artist_id = (SELECT artist_id FROM artists WHERE artist_name = 'Mamie Smith');
